declare
         policy        varchar2(512);
         alldest       number  := dbms_rcvman.FALSE#;
         rlgscn        number;
      begin
         if (:alldest0) then
            alldest := dbms_rcvman.TRUE#;
         end if;
         dbms_rcvman.setRecoveryDestFile(TRUE);
         dbms_rcvman.getRedoLogDeletionPolicy(policy  =policy);
         dbms_rcvman.setRedoLogDeletionPolicy(policy  =policy,
                                              alldest =alldest);
         if ((policy like '%APPLIED%' OR
              policy like '%SHIPPED%') AND
             policy not like '%BACKED UP%') then
            dbms_rcvman.getSCNForAppliedPolicy(
               minscn     =:applied_scn
              , rlgscn     =rlgscn);
         else
            :applied_scn := 0;
         end if;
      end;

declare
         vsn  varchar2(20);
            begin
              vsn := dbms_rcvman.getPackageVersion;
              :pkg_vsn:pkg_vsn_i := vsn;
              if vsn is not null then
                 :pkg_vsnub4 :=
                   to_number(substr(vsn, 1, 2) || substr(vsn, 4, 2) ||
                             substr(vsn, 7, 2) || nvl(substr(vsn, 10, 2), '00'));
              end if;
            end;

